import{g as a,b as e,c as i,h as r}from"./chunks/framework.ebJuSMhv.js";const c=JSON.parse('{"title":"Lumia Honjo/650XL：微软移动在中低端的最后失败","description":"","frontmatter":{"date":"2022-04-04T00:00:00.000Z","title":"Lumia Honjo/650XL：微软移动在中低端的最后失败","tag":["数码","Windows Phone"]},"headers":[],"relativePath":"posts/lumia-650xl-review/index.md","filePath":"posts/lumia-650xl-review/index.md"}'),o={name:"posts/lumia-650xl-review/index.md"};function l(m,p,t,s,n,u){return e(),i("div",null,[...p[0]||(p[0]=[r('<p>2016年，微软发布Lumia650。1+16的骁龙212，纯纯的清库存机。但这还是点燃了一些人的希望：WP还没死透。</p><blockquote><p>Win10 Mobile坚定不移，不会被放弃</p><blockquote><p><em><em>——微软高管 Terry Myerson</em></em></p></blockquote></blockquote><blockquote><p><s>B站可能会倒闭，但永远不会变质</s></p><blockquote><p><s><em><em>——陈睿</em></em></s></p></blockquote></blockquote><p>然而仅仅一年后，微软就停了w10m的功能更新，这说法也成了个笑话。（当然，微软也弄过仙女座之类的补救工作，这就不在本帖讨论范围内了）</p><p>但这次的主角不是Lumia 650，而是它被砍掉的升级版：Lumia 650XL。</p><hr><h3 id="代号「honjo」-lumia-650的更进一步" tabindex="-1">代号「Honjo」:Lumia 650的更进一步 <a class="header-anchor" href="#代号「honjo」-lumia-650的更进一步" aria-label="Permalink to “代号「Honjo」:Lumia 650的更进一步”">​</a></h3><p>Lumia 650XL相对于650的提升不是很大。它的屏幕从5英寸增大到了5.5英寸，电池容量从2000mAh升级为2300mAh，其余配置基本不变。</p><hr><p>值得一提的是，650XL还多了个的前置闪光灯（微软也想搞自拍？）</p><p><img src="/posts/lumia-650xl-review/01.jpg" alt=""> 650XL的设计与650类似，都拥有小奥利奥和Lumia系列常见的聚碳酸酯（塑 料）后盖。虽是塑料，拿在手中却没有一般塑料后壳那种满满的廉价感，手感还挺不错。</p><hr><p><img src="/posts/lumia-650xl-review/02.jpg" alt=""> Lumia650XL（左）和Lumia950盖网版（右），各位觉得哪个好看些？</p><hr><p>相较于650不同的是，650XL的3.5mm耳机接口被放在了屏幕下方，也就是一般手机充电口的位置，而MicroUSB充电口却被放在了顶部。</p><p><img src="/posts/lumia-650xl-review/03.jpg" alt=""> 把耳机接口放底部对于用图中这种耳机的用户格外友好，不过其他的就不得而知了...</p><hr><p>拆开后盖，可以看到一个SD以及两个SIM卡槽，还有此工程机的代号：「Honjo」</p><p><img src="/posts/lumia-650xl-review/04.jpg" alt=""></p><h3 id="奇怪的手机-和奇怪的系统" tabindex="-1">奇怪的手机，和奇怪的系统 <a class="header-anchor" href="#奇怪的手机-和奇怪的系统" aria-label="Permalink to “奇怪的手机，和奇怪的系统”">​</a></h3><p>这台Lumia 650XL搭载了早期的Windows 10 Mobile系统，版本号为10166。</p><p><img src="/posts/lumia-650xl-review/05.png" alt=""></p><hr><p>应用商店早已无法进入，虽然w10m已经可以直接在文件资源管理器中安装应用，但能成功装上的只有一个IT之家。而且10166的SDK早就撤了包，我也没法在上面写UWP。</p><p><img src="/posts/lumia-650xl-review/06.png" alt=""></p><hr><p>尽管此版本的w10m还保留着对安卓应用的支持，但是设置中点击开发者选项后就会卡死然后闪退，所以想在这台650XL上装安卓应用估计是没戏了（</p><hr><p>和其他工程机一样，这个系统内置一堆bug和用于测试的z开头应用。 <img src="/posts/lumia-650xl-review/07.png" alt=""> 乱七八糟的测试软件</p><h3 id="体验与感悟-微软为什么要砍掉它和wp系统" tabindex="-1">体验与感悟:微软为什么要砍掉它和wp系统？ <a class="header-anchor" href="#体验与感悟-微软为什么要砍掉它和wp系统" aria-label="Permalink to “体验与感悟:微软为什么要砍掉它和wp系统？”">​</a></h3><p>试想，若650XL能够成功发售，它能拯救wp吗？ 答案很显然：不能</p><p>在测试和使用Lumia 650XL的时候，我充分地感觉到其配置的拉胯——动不动就死机，自动重启，打开一个应用总是卡在恢复界面——950XL很少有这种情况。</p><p>当然，这也有一大部分原因是其不稳定的测试版系统造成的，而且其定位本身就是中低端。</p><hr><p>归根结底，其最大原因仍然是wp那烂得不行的生态。</p><p>从wp7到wp8，微软已经把开发者和用户们恶心了个遍。直到2014年，微软才意识到wp生态的问题，让开发者可以跨平台构建支持win8.1和wp8.1等平台的应用；在2015年，微软发布通用Windows通用应用平台，也就是我们所说的UWP。</p><p><img src="/posts/lumia-650xl-review/08.jpg" alt=""> UWP的概念（图源m$）</p><hr><p>但这时候已经迟了。尽管UWP有“一次开发，在各平台发布”的强大优势，但其早期API有很大限制：不能拥有多窗口，不能显示悬浮窗，没有真正的后台……这限制了当时许多软件的功能，也造成一众国产老流氓们不愿开发UWP应用。</p><p>虽然在后期的更新中，UWP的限制少了许多，开发也更加简单，但这大都是wp停止功能更新之后的事情了。</p><h3 id="大人-时代变了" tabindex="-1">大人，时代变了 <a class="header-anchor" href="#大人-时代变了" aria-label="Permalink to “大人，时代变了”">​</a></h3><p>微软或许已经知道但wp大势已去，再发布新机也很难改变wp“1%”的命运。</p><p>wp曾在低端的机型占较大优势（Lumia 520曾经以1200万激活量登顶Lumia系列销量之最），而其他性价比手机的崛起，成为压死wp的最后一根稻草。</p><hr><p><img src="/posts/lumia-650xl-review/09.jpg" alt=""> 没有存在感的Lumia 550</p><hr><p><img src="/posts/lumia-650xl-review/10.png" alt=""> 另一个被砍的低端手机「Guilin」，或许是Lumia 555/750（图源诺记吧）</p><hr><p>最后，650XL和555等一众机型一起，死在了大刀部之下。它的被砍，代表的不仅是微软在中低端上的失败，更是整个wp的失败。</p><p>wp，栽在了微软自己挖的坑里。 （正文完）</p>',50)])])}const w=a(o,[["render",l]]);export{c as __pageData,w as default};
